const input = $json;
const question = String(input.question || '').replace(/\s+/g, ' ').trim();
const regressionId = String(input.regression_id || '').trim();
const errors = [];
if (!regressionId) errors.push('missing_regression_id');
if (!question) errors.push('missing_question');
const normalizedQuery = question ? `search_query: ${question}` : '';
return [{ json: {
  ...input,
  regression_id: regressionId,
  question,
  normalized_query: normalizedQuery,
  input_valid: errors.length === 0,
  input_valid_int: errors.length === 0 ? 1 : 0,
  validation_errors: errors,
  evaluation_started_ms: Date.now()
}}];

const state = $items('Validate And Normalize Input')[0].json;
return [{ json: {
  regression_id: state.regression_id || null,
  question: state.question || null,
  expected_action: state.expected_action || null,
  decision: 'invalid_input',
  refusal_reason: 'invalid_evaluation_input',
  errors: state.validation_errors,
  corpus: null,
  stage_1: null,
  reranker: null,
  dedupe_status: 'not_implemented_phase_6',
  top_results: [],
  latency_ms: { embedding: 0, retrieval: 0, reranking: 0, total: Date.now() - state.evaluation_started_ms }
}}];

const state = $items('Validate And Normalize Input')[0].json;
const response = $json;
const body = response.body ?? response;
const statusCode = response.statusCode ?? response.status ?? 0;
const result = body.result || {};
return [{ json: {
  ...state,
  collection_status_code: statusCode,
  collection_ready: statusCode >= 200 && statusCode < 300 && result.status === 'green',
  collection_status: result.status || 'unavailable',
  collection_points_count: Number(result.points_count || 0),
  collection_indexed_vectors_count: Number(result.indexed_vectors_count || 0),
  embedding_started_ms: Date.now()
}}];

const state = $items('Build Collection Metadata')[0].json;
const response = $json;
const body = response.body ?? response;
const vector = body.embedding || body.vector || body.data?.[0]?.embedding || [];
const now = Date.now();
return [{ json: {
  ...state,
  embedding_status_code: response.statusCode ?? response.status ?? 0,
  embedding_latency_ms: now - state.embedding_started_ms,
  embedding_ok: Array.isArray(vector) && vector.length === 768,
  query_vector: vector,
  qdrant_started_ms: now
}}];

const base = $items('Build Embedding Result')[0].json;
const response = $json;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const raw = response.body?.result || response.result || [];
const threshold = Number(base.retrieval_score_threshold ?? 0.55);
const minResultCount = Number(base.min_result_count ?? 3);
const candidates = Array.isArray(raw) ? raw.map((hit, index) => {
  const p = hit.payload || {};
  return {
    qdrant_point_id: String(hit.id),
    retrieval_rank: index + 1,
    retrieval_score: Number(hit.score || 0),
    channel_id: p.channel_id || '',
    channel_name: p.channel || '',
    thread_name: p.thread_name || '',
    first_message_id: p.first_message_id || '',
    message_ids: Array.isArray(p.message_ids) ? p.message_ids.map(String) : [],
    start_ts: p.start_ts || null,
    end_ts: p.end_ts || null,
    authors: Array.isArray(p.authors) ? p.authors : [],
    text: p.text || '',
    payload: p
  };
}) : [];
const passed = candidates.filter(c => c.retrieval_score >= threshold).sort((a,b) => b.retrieval_score - a.retrieval_score);
let refusalReason = null;
if (!base.collection_ready) refusalReason = 'qdrant_collection_unavailable';
else if (!base.embedding_ok) refusalReason = 'embedding_failed';
else if (statusCode < 200 || statusCode >= 300) refusalReason = 'qdrant_failed';
else if (passed.length < minResultCount) refusalReason = 'fewer_than_min_stage_1_results';
return [{ json: {
  ...base,
  query_vector: undefined,
  qdrant_status_code: statusCode,
  qdrant_latency_ms: now - base.qdrant_started_ms,
  raw_candidate_count: candidates.length,
  passed_candidate_count: passed.length,
  candidates,
  passed_stage_1_candidates: passed,
  stage_1_gate_status: refusalReason ? 'refused' : 'passed',
  stage_1_passed_int: refusalReason ? 0 : 1,
  stage_1_refusal_reason: refusalReason,
  reranker_started_ms: now,
  reranker_request: {
    query: base.question,
    candidates: passed.map(c => ({ id: c.qdrant_point_id, text: c.text, metadata: { retrieval_rank: c.retrieval_rank, retrieval_score: c.retrieval_score } }))
  }
}}];

const base = $items('Build Stage 1 Gate And Reranker Request')[0].json;
const response = $json;
const body = response.body ?? response;
const now = Date.now();
const statusCode = response.statusCode ?? response.status ?? 0;
const threshold = Number(base.reranker_score_threshold ?? 0);
const weakThreshold = Number(base.weak_reranker_score_threshold ?? 2);
const byId = new Map((base.passed_stage_1_candidates || []).map(c => [c.qdrant_point_id, c]));
const ranked = (Array.isArray(body.results) ? body.results : []).map((item, index) => {
  const c = byId.get(String(item.id));
  return c ? { ...c, reranker_rank: index + 1, reranker_score: Number(item.reranker_score) } : null;
}).filter(Boolean);
const passed = ranked.filter(c => c.reranker_score > threshold);
let refusalReason = base.stage_1_refusal_reason;
if (!refusalReason && (statusCode < 200 || statusCode >= 300)) refusalReason = 'reranker_failed';
else if (!refusalReason && ranked.length === 0) refusalReason = 'reranker_no_results';
else if (!refusalReason && passed.length < Number(base.min_result_count ?? 3)) refusalReason = 'reranker_score_below_threshold';
const selected = refusalReason ? [] : passed.slice(0, Number(base.context_k ?? 5));
const selectedIds = new Set(selected.map(c => c.qdrant_point_id));
const guildId = '853099205206999050';
const topResults = ranked.slice(0, 10).map(c => ({
  qdrant_point_id: c.qdrant_point_id,
  retrieval_rank: c.retrieval_rank,
  retrieval_score: c.retrieval_score,
  reranker_rank: c.reranker_rank,
  reranker_score: c.reranker_score,
  selected_for_context: selectedIds.has(c.qdrant_point_id),
  channel_id: c.channel_id || null,
  channel_name: c.channel_name || null,
  thread_name: c.thread_name || null,
  first_message_id: c.first_message_id || null,
  message_ids: c.message_ids,
  start_ts: c.start_ts,
  end_ts: c.end_ts,
  authors: c.authors,
  discord_link: c.channel_id && c.first_message_id ? `https://discord.com/channels/${guildId}/${c.channel_id}/${c.first_message_id}` : null,
  text_preview: String(c.text || '').slice(0, 1200),
  gate_status: c.reranker_score > threshold ? 'passed' : 'excluded',
  exclusion_reason: c.reranker_score > threshold ? null : 'reranker_score_below_threshold'
}));
const weakSignal = selected.length > 0 && selected.every(c => c.reranker_score > threshold && c.reranker_score < weakThreshold);
return [{ json: {
  regression_id: base.regression_id,
  category: base.category || null,
  question: base.question,
  normalized_query: base.normalized_query,
  expected_action: base.expected_action || null,
  expected_caveat: base.expected_caveat || null,
  expected_flags: base.expected_flags || null,
  source_area: base.source_area || null,
  evaluator_notes: base.evaluator_notes || null,
  corpus: {
    collection: base.qdrant_collection,
    corpus_version: base.corpus_version,
    status: base.collection_status,
    points_count: base.collection_points_count,
    indexed_vectors_count: base.collection_indexed_vectors_count
  },
  decision: refusalReason ? 'no_context' : 'context_found',
  refusal_reason: refusalReason,
  stage_1: {
    status: base.stage_1_gate_status,
    raw_count: base.raw_candidate_count,
    passed_count: base.passed_candidate_count,
    threshold: Number(base.retrieval_score_threshold),
    minimum_required: Number(base.min_result_count)
  },
  reranker: {
    status: refusalReason && !base.stage_1_refusal_reason ? 'refused' : (base.stage_1_refusal_reason ? 'skipped_after_stage_1_refusal' : 'passed'),
    model: body.model || 'cross-encoder/ms-marco-MiniLM-L-6-v2',
    candidate_count: ranked.length,
    passed_count: passed.length,
    selected_count: selected.length,
    threshold,
    weak_signal_threshold: weakThreshold,
    weak_signal: weakSignal
  },
  dedupe_status: 'not_implemented_phase_6',
  top_results: topResults,
  latency_ms: {
    embedding: base.embedding_latency_ms,
    retrieval: base.qdrant_latency_ms,
    reranking: now - base.reranker_started_ms,
    reranker_service: body.latency_ms ?? null,
    total: now - base.evaluation_started_ms
  }
}}];
